:root{--bg:#07090f;--bg2:#0e1422;--panel:rgba(255,255,255,.07);--panel2:rgba(255,255,255,.115);--border:rgba(255,255,255,.11);--text:#f7fbff;--muted:rgba(247,251,255,.62);--accent:#35d7ff;--accent2:#0b66e4;--good:#39d98a;--warn:#ffc078;--danger:#ff5f7a;--shadow:0 24px 80px rgba(0,0,0,.34);--ease:cubic-bezier(.2,.8,.22,1)}
body.light{--bg:#eef6ff;--bg2:#fff;--panel:rgba(255,255,255,.72);--panel2:rgba(255,255,255,.96);--border:rgba(12,24,40,.12);--text:#101827;--muted:rgba(16,24,39,.62);--shadow:0 20px 65px rgba(20,40,70,.12)}
*{box-sizing:border-box;-webkit-tap-highlight-color:transparent}html{scroll-behavior:smooth}body{margin:0;min-height:100vh;font-family:Cairo,Inter,system-ui,sans-serif;color:var(--text);background:radial-gradient(circle at 20% -10%,rgba(53,215,255,.22),transparent 34%),linear-gradient(160deg,var(--bg),var(--bg2));overflow-x:hidden}body.en{font-family:Inter,Cairo,sans-serif}button,input,textarea,select{font:inherit}button{cursor:pointer}img{max-width:100%}.hidden{display:none!important}.bg-grid{position:fixed;inset:0;pointer-events:none;opacity:.13;background-image:linear-gradient(rgba(255,255,255,.06) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.06) 1px,transparent 1px);background-size:64px 64px;mask-image:linear-gradient(to bottom,#000,transparent 80%)}.ambient{position:fixed;pointer-events:none;border-radius:999px;filter:blur(90px);opacity:.6;animation:float 18s ease-in-out infinite alternate}.ambient-a{width:420px;height:420px;background:rgba(53,215,255,.18);top:-140px;left:8%}.ambient-b{width:330px;height:330px;background:rgba(11,102,228,.18);right:-90px;bottom:12%}@keyframes float{to{transform:translate(40px,28px) scale(1.05)}}
.glass{border:1px solid var(--border);background:linear-gradient(180deg,var(--panel2),var(--panel));box-shadow:var(--shadow);backdrop-filter:blur(18px)}.eyebrow{display:inline-flex;align-items:center;width:max-content;border:1px solid var(--border);border-radius:999px;padding:7px 11px;color:var(--muted);font-size:11px;font-weight:900;letter-spacing:.6px}.primary,.ghost,.round,.link{border:1px solid var(--border);border-radius:18px;min-height:46px;padding:10px 16px;color:var(--text);background:rgba(255,255,255,.055);font-weight:900;transition:.22s var(--ease)}.primary{border:0;color:#021016;background:linear-gradient(135deg,var(--accent),var(--accent2));box-shadow:0 16px 55px rgba(53,215,255,.22)}.primary:hover,.ghost:hover,.round:hover{transform:translateY(-2px)}.big{min-height:58px}.full{width:100%}.round{width:48px;height:48px;border-radius:18px;padding:0}.link{border:0;background:transparent;color:var(--accent);min-height:auto;padding:0}.brand-mark,.brand-mini{display:flex;align-items:center;gap:12px}.brand-mark img{width:64px;height:64px}.brand-mark span{font-size:34px;font-weight:900;letter-spacing:-1px}.brand-mini img{width:35px;height:35px}.brand-mini b{font-size:18px}.pulse img{animation:pulse 2.2s ease-in-out infinite}@keyframes pulse{50%{filter:drop-shadow(0 0 26px rgba(53,215,255,.58));transform:scale(1.05)}}
.loader{position:fixed;inset:0;z-index:999;display:grid;place-items:center;background:#05070c;transition:.65s var(--ease)}.loader.hide{opacity:0;visibility:hidden}.orb{position:absolute;border-radius:999px;filter:blur(70px);opacity:.55}.orb.one{width:300px;height:300px;background:rgba(53,215,255,.2)}.orb.two{width:220px;height:220px;background:rgba(11,102,228,.25);right:18%;bottom:20%}.loader-card{position:relative;width:min(480px,92%);padding:34px;text-align:center;border:1px solid var(--border);border-radius:36px;background:rgba(255,255,255,.065);backdrop-filter:blur(24px)}.loader-card .brand-mark{justify-content:center}.loader-card h1{font-size:30px;margin:18px 0 8px}.loader-card p{color:var(--muted)}.loader-line{height:9px;border-radius:999px;background:rgba(255,255,255,.08);overflow:hidden}.loader-line i{display:block;height:100%;width:38%;border-radius:inherit;background:linear-gradient(90deg,var(--accent),var(--accent2));animation:load 1.2s ease-in-out infinite alternate}@keyframes load{to{width:100%}}
.auth-view{min-height:100vh;position:relative;z-index:1;display:grid;place-items:center;padding:24px}.auth-shell{width:min(1120px,100%);display:grid;grid-template-columns:1.1fr .9fr;gap:18px}.auth-copy,.auth-card{border-radius:42px;padding:36px}.auth-copy{min-height:610px;display:flex;flex-direction:column;justify-content:center}.auth-copy h1{font-size:76px;line-height:1.03;margin:24px 0 14px;letter-spacing:-2px}.auth-copy p,.auth-card p{color:var(--muted);line-height:1.9;font-size:17px}.feature-row{display:flex;gap:9px;flex-wrap:wrap}.feature-row span{border:1px solid var(--border);border-radius:999px;padding:8px 12px;color:var(--muted);font-weight:900;font-size:12px}.live-preview{margin-top:28px;border-radius:26px;padding:18px;max-width:440px}.mini-orbits{display:flex;gap:6px;margin-top:12px}.mini-orbits i{height:9px;border-radius:999px;background:linear-gradient(90deg,var(--accent),var(--accent2));width:45%}.mini-orbits i:nth-child(2){width:22%;opacity:.65}.mini-orbits i:nth-child(3){width:14%;opacity:.45}.auth-card{align-self:center}.auth-card h2{font-size:36px;margin:12px 0 4px}label{display:grid;gap:8px;color:var(--muted);font-weight:800;margin:13px 0}input,textarea,select{width:100%;min-height:50px;border:1px solid var(--border);border-radius:18px;background:rgba(0,0,0,.2);color:var(--text);outline:none;padding:12px 14px}body.light input,body.light textarea,body.light select{background:rgba(255,255,255,.8)}textarea{min-height:140px;resize:vertical}input:focus,textarea:focus,select:focus{border-color:rgba(53,215,255,.55);box-shadow:0 0 0 4px rgba(53,215,255,.12)}small{color:var(--muted)}
.app{min-height:100vh;position:relative;z-index:1;display:grid;grid-template-columns:236px 1fr}.rail{position:sticky;top:0;height:100vh;padding:24px 15px;display:flex;flex-direction:column;justify-content:space-between;border-left:1px solid var(--border);background:rgba(255,255,255,.035);backdrop-filter:blur(24px)}body.light .rail{background:rgba(255,255,255,.68)}#nav{display:grid;gap:8px;margin-top:24px}.nav{height:52px;border:1px solid var(--border);border-radius:19px;background:rgba(255,255,255,.04);color:var(--muted);display:flex;align-items:center;gap:12px;padding:0 14px;font-weight:900;transition:.2s var(--ease)}.nav span{font-size:20px;width:24px;text-align:center}.nav:hover{transform:translateX(-2px);color:var(--text)}.nav.active{border:0;background:linear-gradient(135deg,var(--accent),var(--accent2));color:#021016;box-shadow:0 18px 50px rgba(53,215,255,.22)}.workspace{width:min(1280px,100%);margin:0 auto;padding:28px 34px 110px}.topbar{position:sticky;top:0;z-index:20;display:flex;justify-content:space-between;align-items:flex-start;gap:14px;padding:10px 0 22px;backdrop-filter:blur(16px)}.topbar h1{font-size:38px;margin:2px 0 0}.topbar small{color:var(--muted);font-weight:900}.top-actions{display:flex;gap:10px;align-items:center}.page{display:none;animation:page .32s var(--ease) both}.page.active{display:block}@keyframes page{from{opacity:0;transform:translateY(12px);filter:blur(6px)}to{opacity:1;transform:none;filter:none}}
.center-layout{display:grid;grid-template-columns:1.4fr 1fr 260px;gap:14px}.span-2{grid-column:span 2}.hero-card{min-height:300px;border-radius:38px;padding:34px;display:flex;flex-direction:column;justify-content:center;background:radial-gradient(circle at 20% 0,rgba(53,215,255,.24),transparent 38%),linear-gradient(180deg,var(--panel2),var(--panel))}.hero-card h2{font-size:58px;line-height:1.08;margin:15px 0 10px}.hero-card p{color:var(--muted);font-size:18px;max-width:690px}.hero-actions{display:flex;gap:10px;margin-top:12px;flex-wrap:wrap}.today-score,.stats-card{border-radius:30px;padding:22px}.today-score strong{display:block;font-size:52px;margin:4px 0}.ring{height:12px;border-radius:999px;background:rgba(255,255,255,.09);overflow:hidden}.ring i{display:block;width:0;height:100%;border-radius:inherit;background:linear-gradient(90deg,var(--accent),var(--accent2));transition:.35s}.focus-target{border-radius:30px;padding:24px}.focus-target h3{font-size:32px;margin:10px 0 5px}.focus-target p,.stats-card small,.stats-card span{color:var(--muted)}.stats-card b{display:block;font-size:36px}.next-card,.day-panel,.task-panel,.notes-panel,.dump-card,.dump-result,.insight-main,.profile-card,.settings-card{border-radius:32px;padding:24px}.section-head,.page-head{display:flex;align-items:center;justify-content:space-between;gap:14px;margin-bottom:14px}.section-head h3,.page-head h2{margin:0;font-size:30px}.list{display:grid;gap:10px}.task{border:1px solid var(--border);border-radius:22px;padding:14px;display:flex;justify-content:space-between;align-items:center;gap:12px;background:rgba(255,255,255,.045);transition:.2s var(--ease)}.task:hover{transform:translateY(-2px)}.task.done{opacity:.55}.task.done h4{text-decoration:line-through}.task-main{display:flex;gap:12px;align-items:center}.check{width:38px;height:38px;border:1px solid var(--border);border-radius:14px;display:grid;place-items:center;color:var(--accent);font-weight:900}.task h4{margin:0 0 5px}.meta{display:flex;gap:6px;flex-wrap:wrap}.tag{font-size:11px;border:1px solid var(--border);border-radius:999px;padding:4px 8px;color:var(--muted);font-weight:900}.task-actions{display:flex;gap:6px}.mini{width:37px;height:37px;border:1px solid var(--border);border-radius:14px;background:rgba(255,255,255,.055);color:var(--text)}
.today-layout{display:grid;grid-template-columns:360px 1fr;gap:14px}.day-panel{min-height:280px}.day-panel h2{font-size:46px;margin:14px 0 8px}.day-panel p,.dump-card p,.insight-main p{color:var(--muted);line-height:1.8}.day-controls{display:flex;gap:10px;flex-wrap:wrap;margin-top:16px}.task-panel{min-height:430px}.task-tools{display:grid;grid-template-columns:1fr 170px;gap:10px;margin-bottom:14px}.notes-panel{grid-column:1/-1}.notes-panel textarea{min-height:170px}.focus-room{position:relative;overflow:hidden;min-height:calc(100vh - 145px);border-radius:42px;padding:32px;text-align:center;display:grid;place-items:center;background:radial-gradient(circle at 50% 20%,rgba(53,215,255,.24),transparent 30%),linear-gradient(180deg,var(--panel2),var(--panel))}.focus-room>*{position:relative;z-index:2}.focus-bg i{position:absolute;border-radius:50%;background:rgba(53,215,255,.18);filter:blur(14px);animation:drift 9s infinite alternate}.focus-bg i:nth-child(1){width:90px;height:90px;right:14%;top:18%}.focus-bg i:nth-child(2){width:60px;height:60px;left:16%;bottom:26%;animation-delay:.7s}.focus-bg i:nth-child(3){width:130px;height:130px;right:48%;bottom:12%;animation-delay:1.2s}@keyframes drift{to{transform:translate(30px,-22px) scale(1.2);opacity:.35}}.full-btn{position:absolute;top:22px;left:22px}.focus-room h2{font-size:44px;margin:12px 0}.timer-ring{position:relative;width:300px;height:300px;display:grid;place-items:center}.timer-ring svg{position:absolute;inset:0;transform:rotate(-90deg)}.timer-ring circle{fill:none;stroke:rgba(255,255,255,.09);stroke-width:12}.timer-ring #timerCircle{stroke:url(#x);stroke:var(--accent);stroke-linecap:round;stroke-dasharray:704;stroke-dashoffset:704;transition:.25s}.timer-ring strong{font-size:70px;font-weight:900;text-shadow:0 0 34px rgba(53,215,255,.32)}.focus-controls,.sound-row{display:flex;gap:10px;flex-wrap:wrap;justify-content:center}.sound{border:1px solid var(--border);border-radius:999px;background:rgba(255,255,255,.05);color:var(--text);padding:10px 13px;font-weight:900}.sound.active{background:linear-gradient(135deg,var(--accent),var(--accent2));color:#021016;border:0}.spaces-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:14px}.space{border-radius:30px;padding:22px;min-height:180px;position:relative;overflow:hidden}.space:before{content:"";position:absolute;inset:auto -30px -45px auto;width:150px;height:150px;border-radius:50%;background:var(--space);filter:blur(45px);opacity:.33}.space h3{font-size:28px;margin:10px 0}.space p{color:var(--muted)}.space .space-actions{display:flex;gap:8px;margin-top:14px}.dump-layout,.profile-layout{display:grid;grid-template-columns:1fr 1fr;gap:14px}.dump-card h2,.insight-main h2{font-size:48px;margin:14px 0 8px}.insights-layout{display:grid;grid-template-columns:1fr 260px;gap:14px}.insight-main{grid-row:span 3}.heatmap{display:grid;grid-template-columns:repeat(14,1fr);gap:7px;margin-top:20px}.heat{height:28px;border-radius:8px;background:rgba(255,255,255,.06);border:1px solid var(--border)}.heat.l1{background:rgba(53,215,255,.16)}.heat.l2{background:rgba(53,215,255,.31)}.heat.l3{background:rgba(53,215,255,.55)}.profile-card{text-align:center}.avatar{width:112px;height:112px;border-radius:36px;margin:0 auto 14px;display:grid;place-items:center;font-size:46px;font-weight:900;color:#021016;background:linear-gradient(135deg,var(--accent),var(--accent2))}.profile-card h2{font-size:36px;margin:8px 0}.profile-card p{color:var(--muted)}.level{text-align:right;margin-top:22px}.level span{color:var(--muted);font-weight:900}.level i{display:block;height:12px;border-radius:999px;overflow:hidden;background:rgba(255,255,255,.08);margin-top:8px}.level em{display:block;height:100%;width:0;border-radius:inherit;background:linear-gradient(90deg,var(--accent),var(--accent2))}.two{display:grid;grid-template-columns:1fr 1fr;gap:10px}.modal{position:relative;border-radius:30px;padding:24px;width:min(500px,calc(100vw - 30px))}dialog{border:0;background:transparent;padding:0}dialog::backdrop{background:rgba(0,0,0,.58);backdrop-filter:blur(12px)}.close{position:absolute;top:14px;left:14px;width:38px;height:38px;border-radius:14px;border:1px solid var(--border);background:rgba(255,255,255,.06);color:var(--text);font-size:22px}.cmd{position:fixed;inset:0;z-index:200;display:grid;place-items:start center;padding-top:12vh;background:rgba(0,0,0,.5);backdrop-filter:blur(10px)}.cmd-box{width:min(620px,92%);border-radius:26px;padding:14px}.cmd-item{border:1px solid var(--border);border-radius:17px;padding:13px;margin-top:8px;background:rgba(255,255,255,.06);font-weight:900}.toast{position:fixed;z-index:300;left:50%;bottom:26px;transform:translateX(-50%) translateY(20px);opacity:0;border:1px solid var(--border);border-radius:999px;background:rgba(15,20,30,.86);color:var(--text);padding:11px 16px;backdrop-filter:blur(18px);transition:.25s}.toast.show{opacity:1;transform:translateX(-50%) translateY(0)}.mobile-nav{display:none;position:fixed;z-index:80;left:12px;right:12px;bottom:12px;padding:7px;border:1px solid var(--border);border-radius:28px;background:rgba(12,16,24,.86);backdrop-filter:blur(24px);grid-template-columns:repeat(5,1fr);box-shadow:var(--shadow)}body.light .mobile-nav{background:rgba(255,255,255,.82)}.mnav{border:0;border-radius:20px;background:transparent;color:var(--muted);min-height:54px;display:grid;place-items:center;font-weight:900}.mnav span{font-size:9px}.mnav.active{background:linear-gradient(135deg,var(--accent),var(--accent2));color:#021016}
@media(max-width:1050px){.auth-shell,.today-layout,.dump-layout,.profile-layout{grid-template-columns:1fr}.auth-copy{min-height:auto}.auth-copy h1{font-size:54px}.app{grid-template-columns:1fr}.rail{display:none}.workspace{padding:22px 16px 110px}.mobile-nav{display:grid}.center-layout,.insights-layout{grid-template-columns:1fr}.span-2,.insight-main{grid-column:auto}.topbar{align-items:flex-start}.top-actions{flex-wrap:wrap;justify-content:flex-end}.hero-card h2{font-size:42px}.timer-ring{width:260px;height:260px}.timer-ring strong{font-size:58px}}
@media(max-width:620px){.auth-view{padding:12px}.auth-copy,.auth-card{padding:24px;border-radius:32px}.brand-mark img{width:50px;height:50px}.brand-mark span{font-size:26px}.auth-copy h1{font-size:44px}.topbar{display:block}.top-actions{margin-top:12px;justify-content:stretch}.top-actions button{flex:1}.hero-card,.focus-room{border-radius:30px;padding:22px}.hero-card h2{font-size:34px}.task-tools,.two{grid-template-columns:1fr}.task{align-items:flex-start}.task-actions{flex-direction:column}.spaces-grid{grid-template-columns:1fr}.dump-card h2,.insight-main h2{font-size:36px}}


/* === Navo Polish Phase — safe additive upgrades === */
:root{--motion-fast:.18s;--motion-mid:.32s;--motion-slow:.7s;--surface-glow:0 0 0 1px rgba(255,255,255,.06),0 24px 90px rgba(0,0,0,.30)}
body{scroll-behavior:smooth}.hidden{display:none!important}
.dynamic-aurora{position:fixed;inset:-18%;z-index:0;pointer-events:none;opacity:.55;filter:blur(42px);background:radial-gradient(circle at var(--mx,30%) var(--my,24%),rgba(53,215,255,.22),transparent 24%),radial-gradient(circle at 70% 78%,rgba(124,58,237,.16),transparent 28%),radial-gradient(circle at 18% 90%,rgba(57,217,138,.10),transparent 20%);animation:auroraShift 16s ease-in-out infinite alternate}.star-field{position:fixed;inset:0;z-index:0;pointer-events:none;overflow:hidden}.star-field i{position:absolute;width:3px;height:3px;border-radius:50%;background:rgba(247,251,255,.34);opacity:.28;animation:starFloat var(--d,12s) linear infinite}.star-field i:nth-child(3n){background:rgba(53,215,255,.52)}@keyframes auroraShift{to{transform:translate3d(3%,-2%,0) scale(1.04);opacity:.72}}@keyframes starFloat{from{transform:translate3d(0,14px,0);opacity:.05}50%{opacity:.45}to{transform:translate3d(0,-80px,0);opacity:.04}}
body.light .dynamic-aurora{opacity:.35;filter:blur(52px)}
.glass,.task,.nav,.mnav,.primary,.ghost,.round,.sound,.cmd-item{will-change:transform,opacity}.glass{box-shadow:var(--surface-glow);transform:translateZ(0)}.glass:hover{transform:translateY(-2px) translateZ(0)}.primary,.ghost,.round,.sound,.mini,.cmd-item,.nav,.mnav{transition:transform var(--motion-fast) var(--ease),box-shadow var(--motion-mid) var(--ease),background var(--motion-mid) var(--ease),border-color var(--motion-mid) var(--ease),opacity var(--motion-mid) var(--ease)}.primary:active,.ghost:active,.round:active,.sound:active,.mini:active,.cmd-item:active{transform:scale(.975)}
.page.active .glass,.page.active .task{animation:softRise .44s var(--ease) both}.page.active .glass:nth-child(2){animation-delay:.035s}.page.active .glass:nth-child(3){animation-delay:.07s}.page.active .glass:nth-child(4){animation-delay:.105s}@keyframes softRise{from{opacity:0;transform:translateY(16px) scale(.985);filter:blur(6px)}to{opacity:1;transform:none;filter:none}}
.hero-card{position:relative;overflow:hidden}.hero-card:after{content:"";position:absolute;inset:-40% -20%;background:linear-gradient(110deg,transparent,rgba(255,255,255,.10),transparent);transform:translateX(-80%) rotate(8deg);animation:heroSheen 8s ease-in-out infinite}.hero-card>*{position:relative;z-index:2}@keyframes heroSheen{50%{transform:translateX(80%) rotate(8deg)}100%{transform:translateX(80%) rotate(8deg)}}
.ai-strip{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-top:14px}.ai-pill{border:1px solid var(--border);border-radius:18px;padding:12px;background:rgba(255,255,255,.045);color:var(--muted);font-weight:900;font-size:13px}.ai-pill b{display:block;color:var(--text);font-size:15px;margin-bottom:2px}.ai-pill.good b{color:#8ef5bd}.ai-pill.warn b{color:#ffd08a}.ai-pill.cyan b{color:var(--accent)}
.focus-room{isolation:isolate}.focus-room:before{content:"";position:absolute;inset:0;background:radial-gradient(circle at var(--fx,50%) var(--fy,50%),rgba(53,215,255,.20),transparent 28%);opacity:.72;transition:.2s;z-index:1}.focus-room.running{box-shadow:0 0 0 1px rgba(53,215,255,.18),0 38px 140px rgba(53,215,255,.11)}.focus-room.running .timer-ring{animation:breathe 4s ease-in-out infinite}.focus-room.running #focusTask{text-shadow:0 0 28px rgba(53,215,255,.24)}@keyframes breathe{50%{transform:scale(1.025)}}
.focus-visualizer{height:42px;display:flex;gap:7px;align-items:center;justify-content:center;margin:3px 0 2px}.focus-visualizer i{width:5px;height:10px;border-radius:999px;background:linear-gradient(180deg,var(--accent),var(--accent2));opacity:.55;animation:vizPulse 1.15s ease-in-out infinite alternate}.focus-visualizer i:nth-child(2){animation-delay:.12s}.focus-visualizer i:nth-child(3){animation-delay:.24s}.focus-visualizer i:nth-child(4){animation-delay:.36s}.focus-visualizer i:nth-child(5){animation-delay:.48s}.focus-visualizer i:nth-child(6){animation-delay:.6s}.focus-visualizer i:nth-child(7){animation-delay:.72s}@keyframes vizPulse{to{height:34px;opacity:.95}}
.focus-complete{position:fixed;inset:0;z-index:260;display:grid;place-items:center;background:rgba(0,0,0,.62);backdrop-filter:blur(18px);animation:fadeIn .25s ease both}.focus-complete-card{width:min(420px,calc(100vw - 30px));text-align:center;border:1px solid var(--border);border-radius:34px;padding:34px;background:radial-gradient(circle at 50% 0,rgba(53,215,255,.22),transparent 42%),rgba(14,18,28,.94);box-shadow:0 38px 120px rgba(0,0,0,.46);animation:completePop .38s var(--ease) both}.focus-complete-card h2{font-size:38px;margin:8px 0}.focus-complete-card p{color:var(--muted)}.focus-complete-icon{width:86px;height:86px;border-radius:30px;margin:0 auto 16px;display:grid;place-items:center;font-size:40px;color:#021016;background:linear-gradient(135deg,var(--accent),var(--accent2));box-shadow:0 18px 56px rgba(53,215,255,.26)}@keyframes fadeIn{from{opacity:0}to{opacity:1}}@keyframes completePop{from{opacity:0;transform:translateY(18px) scale(.96)}to{opacity:1;transform:none}}
.cmd-box{transform-origin:top center;animation:cmdDrop .24s var(--ease) both}.cmd-item{display:flex;align-items:center;justify-content:space-between;gap:10px;cursor:pointer}.cmd-item:before{content:'⌘';width:34px;height:34px;border-radius:13px;display:grid;place-items:center;background:rgba(53,215,255,.12);color:var(--accent)}.cmd-item:hover,.cmd-item.selected{transform:translateY(-1px);border-color:rgba(53,215,255,.34);background:rgba(53,215,255,.10)}.cmd-hint{margin:10px 4px 2px;color:var(--muted);font-size:12px;font-weight:900;display:flex;justify-content:space-between}@keyframes cmdDrop{from{opacity:0;transform:translateY(-10px) scale(.98);filter:blur(6px)}to{opacity:1;transform:none;filter:none}}
.space{transition:transform .22s var(--ease),border-color .22s var(--ease),box-shadow .22s var(--ease)}.space:hover{border-color:color-mix(in srgb,var(--space) 40%,var(--border));box-shadow:0 26px 90px color-mix(in srgb,var(--space) 15%,transparent)}
.mobile-safe-pad{height:0}.saving-dot{position:fixed;right:18px;bottom:18px;z-index:301;border:1px solid var(--border);border-radius:999px;padding:8px 12px;background:rgba(15,20,30,.82);backdrop-filter:blur(18px);color:var(--muted);font-weight:900;font-size:12px;opacity:0;transform:translateY(10px);transition:.22s}.saving-dot.show{opacity:1;transform:none}
@media(max-width:620px){body{background-attachment:fixed}.workspace{padding-inline:12px}.topbar{position:relative}.top-actions{display:grid;grid-template-columns:1fr 1fr;gap:8px}.top-actions #logout{display:none}.hero-card{min-height:255px}.ai-strip{grid-template-columns:1fr}.today-score strong{font-size:42px}.timer-ring{width:236px!important;height:236px!important}.timer-ring strong{font-size:48px!important}.focus-controls button{flex:1;min-width:95px}.sound-row{display:grid;grid-template-columns:repeat(4,1fr);width:100%}.sound{padding:9px 4px;font-size:12px}.mobile-nav{left:9px;right:9px;bottom:9px;border-radius:24px}.mnav{min-height:50px}.cmd{padding-top:7vh}.cmd-box{width:calc(100vw - 18px)}}
@media(prefers-reduced-motion:reduce){*,*:before,*:after{animation:none!important;transition:none!important;scroll-behavior:auto!important}.dynamic-aurora,.star-field{display:none!important}}

/* === Navo Cloud Edition — gentle cursor + account sync polish === */
body.mouse-off .dynamic-aurora{background:radial-gradient(circle at 34% 22%,rgba(53,215,255,.14),transparent 24%),radial-gradient(circle at 70% 78%,rgba(124,58,237,.12),transparent 28%),radial-gradient(circle at 18% 90%,rgba(57,217,138,.08),transparent 20%)!important;opacity:.38!important;filter:blur(58px)!important}
body.mouse-soft .dynamic-aurora{opacity:.30!important;filter:blur(70px)!important;transition:background-position .8s ease,opacity .4s ease}
body.mouse-full .dynamic-aurora{opacity:.46!important;filter:blur(56px)!important}
.auth-cloud-box{margin:14px 0;border:1px solid var(--border);border-radius:22px;padding:14px;background:rgba(255,255,255,.045)}
.cloud-toggle{display:flex;align-items:center;justify-content:space-between;gap:12px;margin:0;color:var(--text)}
.cloud-toggle input{width:44px;min-height:24px;appearance:none;border-radius:999px;padding:0;background:rgba(255,255,255,.10);position:relative;transition:.22s}
.cloud-toggle input:before{content:"";position:absolute;width:18px;height:18px;right:3px;top:2px;border-radius:999px;background:var(--muted);transition:.22s}
.cloud-toggle input:checked{background:linear-gradient(135deg,var(--accent),var(--accent2))}.cloud-toggle input:checked:before{right:21px;background:#021016}
#cloudEmailLogin{margin-top:10px}.auth-cloud-help{display:block;margin-top:8px;color:var(--muted);font-size:12px;line-height:1.7}
.cloud-badge{position:fixed;right:18px;top:18px;z-index:302;border:1px solid var(--border);border-radius:999px;padding:8px 12px;background:rgba(15,20,30,.82);backdrop-filter:blur(18px);color:var(--muted);font-weight:900;font-size:12px;display:flex;align-items:center;gap:8px;opacity:.92}.cloud-badge i{width:8px;height:8px;border-radius:50%;background:var(--muted);box-shadow:0 0 18px rgba(255,255,255,.16)}.cloud-badge.calm i{background:var(--muted);box-shadow:0 0 18px rgba(255,255,255,.16)}.cloud-badge.synced i{background:var(--good);box-shadow:0 0 18px var(--good)}.cloud-badge.syncing i{background:var(--accent);box-shadow:0 0 18px var(--accent);animation:pulse 1s infinite}.cloud-badge.offline i{background:var(--danger);box-shadow:0 0 18px var(--danger)}
.cloud-account-card{grid-column:1/-1}.muted-line{color:var(--muted);line-height:1.8}.cloud-status-row{display:flex;align-items:center;justify-content:space-between;gap:12px;border:1px solid var(--border);border-radius:18px;padding:12px;background:rgba(255,255,255,.045);margin:12px 0}.cloud-status-row span{color:var(--muted);font-weight:900}.cloud-status-row b{font-size:13px;direction:ltr;text-align:left}
.account-chip-row{display:flex;gap:8px;flex-wrap:wrap;margin:12px 0}.account-chip{border:1px solid var(--border);border-radius:999px;padding:8px 11px;background:rgba(255,255,255,.045);font-size:12px;color:var(--muted);font-weight:900}.account-chip.good{color:#8ef5bd}.account-chip.cyan{color:var(--accent)}
@media(max-width:620px){.cloud-badge{top:auto;bottom:78px;right:12px}.cloud-status-row{display:grid}.cloud-status-row b{text-align:right}}


/* === Product polish final pass === */
body.mouse-off .star-field{opacity:.18!important}
body.mouse-soft .star-field{opacity:.22!important}
.auth-card{position:relative;overflow:hidden}.auth-card:before{content:"";position:absolute;inset:0 0 auto 0;height:1px;background:linear-gradient(90deg,transparent,var(--accent),transparent);opacity:.55}.auth-card>*,.auth-cloud-box{position:relative}
.auth-cloud-box input[type=email]{direction:ltr;text-align:left;font-family:Inter,Cairo,sans-serif}
.cloud-badge{letter-spacing:.1px}.cloud-badge.calm{opacity:.72}.cloud-badge.offline{opacity:.82}
.hero-card h2,.auth-copy h1{letter-spacing:-1.5px}.task,.glass{will-change:transform}.task:hover{transform:translateY(-1px)}
.focus-room{overflow:hidden}.focus-room:after{content:"";position:absolute;inset:auto 18% 10% 18%;height:1px;background:linear-gradient(90deg,transparent,var(--accent),transparent);opacity:.35;filter:blur(.2px)}
@media(max-width:760px){.auth-shell{gap:18px}.auth-copy h1{font-size:clamp(42px,12vw,70px)}.cloud-badge{font-size:11px;padding:7px 10px}.hero-card h2{font-size:clamp(30px,9vw,58px)}}
